SELECT count(*) FROM hm_query.inventory_health_flat

    AND sku LIKE CONCAT('%', #{sku}, '%')
    AND product_name LIKE CONCAT('%', #{productName}, '%')
    AND product_id = #{productId}
    AND seller_id = #{sellerId}
    AND seller_name LIKE CONCAT('%', #{sellerName}, '%')
    AND stock_status = #{stockStatus}
    AND stm_state = #{stmState}
    AND warehouse_name = #{warehouseName}
    AND (sku LIKE CONCAT('%', #{q}, '%') OR product_name LIKE CONCAT('%', #{q}, '%') OR seller_name LIKE CONCAT('%', #{q}, '%'))

SELECT id, sku, product_id as "productId", product_name as "productName", category_name as "categoryName", seller_id as "sellerId", seller_name as "sellerName", warehouse_name as "warehouseName", warehouse_code as "warehouseCode", variant_id as "variantId", available_qty as "availableQuantity", reserved_qty as "reserved", damaged_qty as "damagedQuantity", inbound_qty as "inboundQuantity", low_stock_threshold as "lowStockThreshold", stock_status as "status", stm_state as "stateId", days_of_supply as "daysOfSupply", avg_daily_sales as "avgDailySales", last_sale_at as "lastSaleAt", last_restock_at as "lastRestockAt", cost_price as "costPrice", locked_capital as "lockedCapital", days_without_sale as "daysWithoutSale" FROM hm_query.inventory_health_flat
AND sku LIKE CONCAT('%', #{sku}, '%') AND product_name LIKE CONCAT('%', #{productName}, '%') AND product_id = #{productId} AND seller_id = #{sellerId} AND seller_name LIKE CONCAT('%', #{sellerName}, '%') AND stock_status = #{stockStatus} AND stm_state = #{stmState} AND warehouse_name = #{warehouseName} AND (sku LIKE CONCAT('%', #{q}, '%') OR product_name LIKE CONCAT('%', #{q}, '%') OR seller_name LIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT count(*) FROM hm_query.inventory_health_flat
WHERE stock_status = 'LOW_STOCK'
AND warehouse_name = #{warehouseName}
AND seller_id = #{sellerId}

SELECT count(*) FROM hm_query.stock_movement_flat

    AND movement_type = #{movementType}
    AND sku LIKE CONCAT('%', #{sku}, '%')
    AND warehouse_name = #{warehouseName}

SELECT id, movement_type as "type", sku as "sku", product_name as "productName", quantity as "quantity", warehouse_name as "warehouseName", reason as "reason", reference_id as "referenceId", performed_by as "performedBy", movement_time as "movementTime" FROM hm_query.stock_movement_flat
AND movement_type = #{movementType} AND sku LIKE CONCAT('%', #{sku}, '%') AND warehouse_name = #{warehouseName}
${orderby} ${pagination}
